class Solution:
    def solve(self, nums: list[int], target: int) -> bool:
        n = len(nums)
        left = 0
        right = n - 1
        while left <= right:
            mid = left + (right - left) // 2
            if nums[mid] == target:
                return True
            elif nums[mid] < target:
                left = mid + 1
            else:
                right = mid - 1
        return False

def main():
    s = Solution()
    n = int(input())
    nums = list(map(int, input().split()))
    target = int(input())
    print(s.solve(nums, target))

